Javascript.isReadOnly:
var allWarrants = Services.getValue(AllWarrants.dataBinding);
if (! CaseManUtils.isBlank(allWarrants))
{
	if (allWarrants == "Y")
	{
		return true;
	}
	else
	{
		return false;
	}
}
else
{
	//TD4183 Kevin Gichohi (EDS) - 10 Aug 2006: The warrant number field should be read only if the box is unchecked on entry i.e. allWarrants is blank or null.
	return false;
}

Javascript.logic:
var allWarrants = Services.getValue(AllWarrants.dataBinding);
if (! CaseManUtils.isBlank(allWarrants))
{
	if (allWarrants == "Y")
	{
		Services.setValue(WarrantNumber.dataBinding, "");
	}
}		
var caseNumber = Services.getValue(CaseNumber.dataBinding);
var warrantNumber = Services.getValue(WarrantNumber.dataBinding);	
if (!CaseManUtils.isBlank(caseNumber) && !CaseManUtils.isBlank(warrantNumber))
{
	searchWarrants();
	
}

Javascript.miscCode:

	function searchWarrants()
	{
		var warrantNumber = Services.getValue(WarrantNumber.dataBinding);	
		var caseNumber = Services.getValue(CaseNumber.dataBinding);				
	    //Call Search Service now
		var params = new ServiceParams();
		params.addSimpleParameter("warrantNumber", warrantNumber);
		params.addSimpleParameter("caseNumber", caseNumber);
		
		//Wildcard search removed, might as well delete them.
		/*
		params.addSimpleParameter("localNumber", "%");
		params.addSimpleParameter("CONumber", "%");
		params.addSimpleParameter("issueDate", "%");
		params.addSimpleParameter("issuedBy", "%");
		*/
		
		//Services.callService("searchWarrants", params, WarrantNumber, true);	
		
		/* TD4181: Kevin Gichohi (EDS): 14 August 2006. The service above returned warrants that were issued by the current
		 * user logged in court. The report looked for warrants that are currently owned by and executed by
		 * the user logged in court. The net result was that only warrants that are issued by, currently owned by
		 * and executed by the user logged in court were being printed. 
		 * The service below searches for warrants that are currently owned by and executed by the user logged in court.
		 * Hence foreign warrants will also be included.  
		 */
		
		Services.callService("searchWarrantsForReissue", params, WarrantNumber, true);
		
	}
	
	WarrantNumber.onSuccess = function(dom) {
	    if(dom != null) {
	        var node = dom.selectSingleNode("/ds/Warrants");
	        Services.replaceNode(SEARCH_RESULTS_XPATH, node);
	        
	        var count = Services.countNodes(SEARCH_RESULTS_XPATH + "/Warrant");
	        if(count == 0) {
	           alert(Messages.NO_RESULTS_MESSAGE); 
	           var errCode = ErrorCode.getErrorCode("CaseMan_caseWarrantNumberNotFound_Msg");
	           faildedValidation (errCode);
	        } else if(count >= 1) {
	        	//alert("Valid Warrant Number"); 
	        }
	    }
	}
	
	function validateWarrant()
	{
		var errCode = null;
		var count = Services.countNodes(SEARCH_RESULTS_XPATH + "/Warrant");
		if(count == 0) {
           errCode = ErrorCode.getErrorCode("CaseMan_caseWarrantNumberNotFound_Msg");
        }
        return errCode;
	}
